const state = $input.first().json;

// ── 1. DOCUSAURUS DRIFT ──────────────────────────────────────
// Features that have no corresponding doc page
const featureToPart = {
  'dashboard': 'intro',
  'auth': null, // internal, no public docs
  'settings': null,
  'help': null,
  'abby-ai': null, // AI assistant, internal
  'data-sources': 'part1-getting-started',
  'vocabulary': 'part2-vocabulary',
  'concept-sets': 'part2-vocabulary',
  'cohort-definitions': 'part3-cohorts',
  'analyses': 'part4-analyses',
  'estimation': 'part4-analyses',
  'prediction': 'part4-analyses',
  'pathways': 'part4-analyses',
  'sccs': 'part4-analyses',
  'evidence-synthesis': 'part4-analyses',
  'ingestion': 'part5-ingestion',
  'data-explorer': 'part6-data-explorer',
  'profiles': 'part7-patient-profiles',
  'administration': 'part8-administration',
  'genomics': 'part9-genomics',
  'imaging': 'part10-imaging',
  'heor': 'part11-heor',
  'studies': 'part4-analyses',
  'jobs': null, // utility, no dedicated docs
  'care-gaps': null, // future feature
  'publish': null, // internal
  'radiogenomics': null, // future
};

const docPages = Object.keys(state.docusaurus_pages);
const recentDevlogs = state.recent_devlogs || [];

// Find features missing docs
const docsDrift = [];
for (const feature of state.frontend_features) {
  const part = featureToPart[feature];
  if (part === null || part === undefined) continue; // excluded
  // Check if any doc page path contains the part directory
  const hasDoc = docPages.some(p => p.startsWith(part + '/'));
  if (!hasDoc && part !== 'intro') {
    docsDrift.push({ feature, expectedPart: part, reason: 'no_doc_page' });
  }
}

// Find devlogs newer than their doc pages
const devlogDrift = [];
for (const devlog of recentDevlogs) {
  // Match devlog to doc page by keywords
  const keywords = devlog.path.toLowerCase().replace(/[-.]/g, ' ').split(/\s+/);
  for (const [pagePath, pageInfo] of Object.entries(state.docusaurus_pages)) {
    const pageKeywords = pagePath.toLowerCase().replace(/[-.]/g, ' ');
    const overlap = keywords.filter(k => k.length > 3 && pageKeywords.includes(k));
    if (overlap.length >= 2 && devlog.mtime > pageInfo.mtime) {
      devlogDrift.push({
        devlog: devlog.path,
        doc_page: pagePath,
        devlog_excerpt: devlog.excerpt.substring(0, 1500),
        reason: 'devlog_newer_than_doc'
      });
    }
  }
}

// ── 2. HELP JSON DRIFT ───────────────────────────────────────
const helpFiles = Object.keys(state.help_files);
const routeMapping = state.route_help_mapping;

const helpDrift = [];
// Routes that reference help keys without a corresponding JSON file
for (const [route, helpKey] of Object.entries(routeMapping)) {
  if (!helpFiles.includes(helpKey)) {
    helpDrift.push({ route, helpKey, reason: 'missing_help_json' });
  }
}
// Help files where docs_url points to non-existent page
for (const [key, info] of Object.entries(state.help_files)) {
  if (info.docs_url) {
    const docPath = info.docs_url.replace(/^\/docs\//, '').replace(/\/$/, '');
    const matchesAnyPage = docPages.some(p => {
      const pageId = state.docusaurus_pages[p]?.id || '';
      return p.includes(docPath) || pageId === docPath;
    });
    if (!matchesAnyPage && docPath && docPath !== '#') {
      helpDrift.push({ helpKey: key, docs_url: info.docs_url, reason: 'broken_docs_link' });
    }
  }
}
// Features with routes but no help entry in route mapping
const routeFeatures = new Set(Object.values(routeMapping));
for (const feature of state.frontend_features) {
  const helpKey = feature.replace(/-/g, '-');
  // Check common patterns
  const possibleKeys = [helpKey, helpKey.replace('definitions', 'builder'), helpKey.replace('concept-sets', 'concept-set-builder')];
  const hasMapped = possibleKeys.some(k => routeFeatures.has(k));
  const excluded = ['auth', 'settings', 'help', 'abby-ai', 'estimation', 'prediction', 'pathways', 'sccs', 'evidence-synthesis', 'radiogenomics', 'publish'];
  if (!hasMapped && !excluded.includes(feature)) {
    helpDrift.push({ feature, reason: 'no_route_help_mapping' });
  }
}

// ── SUMMARY ──────────────────────────────────────────────────
const totalDrift = docsDrift.length + devlogDrift.length + helpDrift.length;

return [{
  json: {
    totalDrift,
    docsDrift,
    devlogDrift,
    helpDrift,
    // Pass through for Claude context
    frontendFeatures: state.frontend_features,
    helpFiles: state.help_files,
    docPages: state.docusaurus_pages,
    routeMapping: state.route_help_mapping,
    recentDevlogs: (state.recent_devlogs || []).slice(0, 5),
    gitLogWeek: (state.git_log_week || []).slice(0, 30),
    sidebarsRaw: state.sidebars?.raw || '',
  }
}];

const d = $('Detect Drift').first().json;
const hasDocs = d.docsDrift.length > 0 || d.devlogDrift.length > 0;
const hasHelp = d.helpDrift.length > 0;

// Build prompts for each branch that has drift
const results = [];

if (hasDocs) {
  // Build context for Docusaurus updates
  const devlogContext = d.devlogDrift.map(dl => `DEVLOG: ${dl.devlog}
CORRESPONDING DOC: ${dl.doc_page}
DEVLOG CONTENT:
${dl.devlog_excerpt}`).join('
---
');
  const missingDocs = d.docsDrift.map(dd => `Feature: ${dd.feature} → Expected in: ${dd.expectedPart}/`).join('
');
  const recentCommits = d.gitLogWeek.slice(0, 20).map(c => `${c.hash} ${c.message}`).join('
');
  const recentDevlogs = d.recentDevlogs.map(dl => `${dl.path}: ${dl.excerpt.substring(0, 500)}`).join('
---
');

  results.push({
    branch: 'docusaurus',
    prompt: `You are updating the Parthenon Docusaurus user manual. Parthenon is a unified OHDSI outcomes research platform for healthcare analytics.

CURRENT SIDEBARS.TS:
${d.sidebarsRaw}

DRIFT DETECTED:

MISSING DOCUMENTATION:
${missingDocs || 'None'}

STALE DOCUMENTATION (devlog is newer than doc page):
${devlogContext || 'None'}

RECENT COMMITS (7 days):
${recentCommits}

RECENT DEVLOG EXCERPTS:
${recentDevlogs}

For each piece of drift, generate the updated or new MDX content. Return your response as a JSON object with this exact structure:
{
  "pages": [
    {"path": "relative/path/to/file.mdx", "content": "---
id: page-id
title: ...
sidebar_label: ...
---

Full MDX content..."}
  ],
  "sidebars_ts": "full updated sidebars.ts content (only if new pages were added, otherwise null)"
}

Rules:
- Match the existing dark clinical documentation style
- Use proper MDX frontmatter (id, title, sidebar_label)
- Include practical examples and tables where appropriate
- Reference OMOP CDM v5.4 concepts accurately
- Keep content focused on user workflows, not implementation details
- Only update pages that actually need changes — do not regenerate unchanged content
- Return ONLY valid JSON, no markdown code fences`,
    drift: d.docsDrift.concat(d.devlogDrift),
  });
}

if (hasHelp) {
  const helpContext = d.helpDrift.map(h => {
    if (h.reason === 'missing_help_json') return `MISSING: Route ${h.route} → help key "${h.helpKey}" has no JSON file`;
    if (h.reason === 'broken_docs_link') return `BROKEN LINK: Help file "${h.helpKey}" links to ${h.docs_url} which doesn't exist`;
    if (h.reason === 'no_route_help_mapping') return `UNMAPPED: Feature "${h.feature}" has no route→help mapping in Sidebar.tsx`;
    return JSON.stringify(h);
  }).join('
');

  const existingHelp = Object.entries(d.helpFiles).slice(0, 5).map(([k, v]) => `"${k}": title="${v.title}", docs_url="${v.docs_url}", tips=${v.tip_count}`).join('
');

  results.push({
    branch: 'help',
    prompt: `You are updating the contextual help system for the Parthenon platform. Each help topic is a JSON file in backend/resources/help/.

EXISTING HELP FILES (sample):
${existingHelp}

CURRENT ROUTE MAPPING:
${JSON.stringify(d.routeMapping, null, 2)}

DRIFT DETECTED:
${helpContext}

AVAILABLE DOC PAGES:
${Object.keys(d.docPages).join('
')}

For each piece of drift, generate the fix. Return your response as a JSON object:
{
  "help_files": [
    {"key": "help-key-name", "content": {"key": "help-key-name", "title": "Feature Title", "description": "Overview paragraph explaining the feature and its purpose in clinical research.", "docs_url": "/docs/path/to/chapter", "video_url": null, "tips": ["Practical tip 1", "Practical tip 2", "Practical tip 3"]}}
  ],
  "route_mapping_additions": {"new-route": "help-key"}
}

Rules:
- Match the clinical/research tone of existing help files
- docs_url must point to an actual Docusaurus page path (use /docs/ prefix)
- Include 3-5 practical tips per help file
- video_url should be null (no videos exist yet)
- Return ONLY valid JSON, no markdown code fences`,
    drift: d.helpDrift,
  });
}

return results.map(r => ({ json: r }));

// Collect all Claude responses and merge into a single write payload
const items = $input.all();
const promptItems = $('Build Branch Prompts').all();

const writePayload = {
  docusaurus: [],
  sidebars_ts: null,
  help: [],
  sidebar_tsx_mapping: null,
};

const summary = { docusaurus: 0, help: 0, errors: [] };

for (let i = 0; i < items.length; i++) {
  const response = items[i].json;
  const branch = promptItems[i]?.json?.branch || 'unknown';

  let parsed = null;
  try {
    const text = response.content?.[0]?.text || '';
    // Try to extract JSON from the response (handle markdown fences)
    const jsonMatch = text.match(/```json\s*([\s\S]*?)```/) || text.match(/\{[\s\S]*\}/);
    const jsonStr = jsonMatch ? (jsonMatch[1] || jsonMatch[0]) : text;
    parsed = JSON.parse(jsonStr);
  } catch (e) {
    summary.errors.push(`Failed to parse ${branch} response: ${e.message}`);
    continue;
  }

  if (branch === 'docusaurus' && parsed.pages) {
    for (const page of parsed.pages) {
      if (page.path && page.content) {
        writePayload.docusaurus.push({ path: page.path, content: page.content });
        summary.docusaurus++;
      }
    }
    if (parsed.sidebars_ts) {
      writePayload.sidebars_ts = parsed.sidebars_ts;
    }
  }

  if (branch === 'help') {
    if (parsed.help_files) {
      for (const hf of parsed.help_files) {
        if (hf.key && hf.content) {
          writePayload.help.push({ key: hf.key, content: hf.content });
          summary.help++;
        }
      }
    }
    if (parsed.route_mapping_additions && Object.keys(parsed.route_mapping_additions).length > 0) {
      // Merge with existing mapping
      const existing = promptItems.find(p => p.json.branch === 'help');
      const currentMapping = $('Detect Drift').first().json.routeMapping || {};
      writePayload.sidebar_tsx_mapping = { ...currentMapping, ...parsed.route_mapping_additions };
    }
  }

}

const totalChanges = summary.docusaurus + summary.help;

return [{
  json: {
    writePayload,
    summary,
    totalChanges,
    hasChanges: totalChanges > 0,
  }
}];
